/**
 * @file fft_radix12_avx2_dit_tw_log3.h
 * @brief DFT-12 AVX2 DIT twiddled (log3)
 *
 * 4x3 CT, k-step=4
 * Generated by gen_radix12.py
 *
 * -- Operation counts per k-step --
 *
 *   kernel                 add   sub   mul   neg   fma   fms | arith flops |  ld  st  sp  rl  mem
 *   -------------------- ----- ----- ----- ----- ----- ----- + ----- ----- + --- --- --- --- ----
 *   bwd                     40    32    50     3    49    25 |   199   273 |  26  24  12  12   74
 *   fwd                     40    32    50     3    49    25 |   199   273 |  26  24  12  12   74
 *
 */

#ifndef FFT_RADIX12_AVX2_DIT_TW_LOG3_H
#define FFT_RADIX12_AVX2_DIT_TW_LOG3_H

#include <immintrin.h>

#ifndef FFT_W12_TWIDDLES_DEFINED
#define FFT_W12_TWIDDLES_DEFINED
static const double W12_1_re = 8.66025403784438707611e-01;
static const double W12_1_im = -4.99999999999999944489e-01;
static const double W12_2_re = 5.00000000000000111022e-01;
static const double W12_2_im = -8.66025403784438596588e-01;
static const double W12_3_re = 6.12323399573676603587e-17;
static const double W12_3_im = -1.00000000000000000000e+00;
static const double W12_4_re = -4.99999999999999777955e-01;
static const double W12_4_im = -8.66025403784438707611e-01;
static const double W12_6_re = -1.00000000000000000000e+00;
static const double W12_6_im = -1.22464679914735320717e-16;
#endif

#ifndef R12A_LD
#define R12A_LD(p) _mm256_load_pd(p)
#define R12A_ST(p,v) _mm256_store_pd((p),(v))
#endif
#define LD R12A_LD
#define ST R12A_ST

static __attribute__((target("avx2,fma"))) void
radix12_tw_log3_dit_kernel_fwd_avx2(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ tw_re, const double * __restrict__ tw_im,
    size_t K)
{
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d KHALF = _mm256_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m256d KS = _mm256_set1_pd(0.866025403784438596588302061718422919511795044);

    __attribute__((aligned(32))) double spill_re[48];
    __attribute__((aligned(32))) double spill_im[48];

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im;

    const __m256d tw_W12_1_re = _mm256_set1_pd(W12_1_re);
    const __m256d tw_W12_1_im = _mm256_set1_pd(W12_1_im);
    const __m256d tw_W12_2_re = _mm256_set1_pd(W12_2_re);
    const __m256d tw_W12_2_im = _mm256_set1_pd(W12_2_im);
    const __m256d tw_W12_4_re = _mm256_set1_pd(W12_4_re);
    const __m256d tw_W12_4_im = _mm256_set1_pd(W12_4_im);

    for (size_t k = 0; k < K; k += 4) {
        /* Log3: load W^1, derive W^2..W^11 (10 cmuls, depth-4 parallel chain) */
        const __m256d w1r = _mm256_load_pd(&tw_re[0*K+k]), w1i = _mm256_load_pd(&tw_im[0*K+k]);
        __m256d w2r, w2i;
        w2r = _mm256_fmsub_pd(w1r,w1r,_mm256_mul_pd(w1i,w1i));
        w2i = _mm256_fmadd_pd(w1r,w1i,_mm256_mul_pd(w1i,w1r));
        __m256d w3r, w3i;
        w3r = _mm256_fmsub_pd(w1r,w2r,_mm256_mul_pd(w1i,w2i));
        w3i = _mm256_fmadd_pd(w1r,w2i,_mm256_mul_pd(w1i,w2r));
        __m256d w4r, w4i;
        w4r = _mm256_fmsub_pd(w2r,w2r,_mm256_mul_pd(w2i,w2i));
        w4i = _mm256_fmadd_pd(w2r,w2i,_mm256_mul_pd(w2i,w2r));
        __m256d w5r, w5i;
        w5r = _mm256_fmsub_pd(w1r,w4r,_mm256_mul_pd(w1i,w4i));
        w5i = _mm256_fmadd_pd(w1r,w4i,_mm256_mul_pd(w1i,w4r));
        __m256d w6r, w6i;
        w6r = _mm256_fmsub_pd(w3r,w3r,_mm256_mul_pd(w3i,w3i));
        w6i = _mm256_fmadd_pd(w3r,w3i,_mm256_mul_pd(w3i,w3r));
        __m256d w7r, w7i;
        w7r = _mm256_fmsub_pd(w3r,w4r,_mm256_mul_pd(w3i,w4i));
        w7i = _mm256_fmadd_pd(w3r,w4i,_mm256_mul_pd(w3i,w4r));
        __m256d w8r, w8i;
        w8r = _mm256_fmsub_pd(w4r,w4r,_mm256_mul_pd(w4i,w4i));
        w8i = _mm256_fmadd_pd(w4r,w4i,_mm256_mul_pd(w4i,w4r));
        __m256d w9r, w9i;
        w9r = _mm256_fmsub_pd(w4r,w5r,_mm256_mul_pd(w4i,w5i));
        w9i = _mm256_fmadd_pd(w4r,w5i,_mm256_mul_pd(w4i,w5r));
        __m256d w10r, w10i;
        w10r = _mm256_fmsub_pd(w5r,w5r,_mm256_mul_pd(w5i,w5i));
        w10i = _mm256_fmadd_pd(w5r,w5i,_mm256_mul_pd(w5i,w5r));
        __m256d w11r, w11i;
        w11r = _mm256_fmsub_pd(w5r,w6r,_mm256_mul_pd(w5i,w6i));
        w11i = _mm256_fmadd_pd(w5r,w6i,_mm256_mul_pd(w5i,w6r));

        /* sub-FFT n2=0 */
        x0_re = LD(&in_re[0*K+k]);
        x0_im = LD(&in_im[0*K+k]);
        x1_re = LD(&in_re[3*K+k]);
        x1_im = LD(&in_im[3*K+k]);
        { __m256d tr = x1_re;
          x1_re = _mm256_fmsub_pd(x1_re,w3r,_mm256_mul_pd(x1_im,w3i));
          x1_im = _mm256_fmadd_pd(tr,w3i,_mm256_mul_pd(x1_im,w3r)); }
        x2_re = LD(&in_re[6*K+k]);
        x2_im = LD(&in_im[6*K+k]);
        { __m256d tr = x2_re;
          x2_re = _mm256_fmsub_pd(x2_re,w6r,_mm256_mul_pd(x2_im,w6i));
          x2_im = _mm256_fmadd_pd(tr,w6i,_mm256_mul_pd(x2_im,w6r)); }
        x3_re = LD(&in_re[9*K+k]);
        x3_im = LD(&in_im[9*K+k]);
        { __m256d tr = x3_re;
          x3_re = _mm256_fmsub_pd(x3_re,w9r,_mm256_mul_pd(x3_im,w9i));
          x3_im = _mm256_fmadd_pd(tr,w9i,_mm256_mul_pd(x3_im,w9r)); }

        /* radix-4 n2=0 [fwd] */
        {
        __m256d sr=_mm256_add_pd(x0_re,x2_re), si=_mm256_add_pd(x0_im,x2_im);
        __m256d dr=_mm256_sub_pd(x0_re,x2_re), di=_mm256_sub_pd(x0_im,x2_im);
        __m256d tr=_mm256_add_pd(x1_re,x3_re), ti=_mm256_add_pd(x1_im,x3_im);
        __m256d ur=_mm256_sub_pd(x1_re,x3_re), ui=_mm256_sub_pd(x1_im,x3_im);
        x0_re=_mm256_add_pd(sr,tr); x0_im=_mm256_add_pd(si,ti);
        x2_re=_mm256_sub_pd(sr,tr); x2_im=_mm256_sub_pd(si,ti);
        x1_re=_mm256_add_pd(dr,ui); x1_im=_mm256_sub_pd(di,ur);
        x3_re=_mm256_sub_pd(dr,ui); x3_im=_mm256_add_pd(di,ur);
        }

        _mm256_store_pd(&spill_re[0*4], x0_re);
        _mm256_store_pd(&spill_im[0*4], x0_im);
        _mm256_store_pd(&spill_re[1*4], x1_re);
        _mm256_store_pd(&spill_im[1*4], x1_im);
        _mm256_store_pd(&spill_re[2*4], x2_re);
        _mm256_store_pd(&spill_im[2*4], x2_im);
        _mm256_store_pd(&spill_re[3*4], x3_re);
        _mm256_store_pd(&spill_im[3*4], x3_im);

        /* sub-FFT n2=1 */
        x0_re = LD(&in_re[1*K+k]);
        x0_im = LD(&in_im[1*K+k]);
        { __m256d tr = x0_re;
          x0_re = _mm256_fmsub_pd(x0_re,w1r,_mm256_mul_pd(x0_im,w1i));
          x0_im = _mm256_fmadd_pd(tr,w1i,_mm256_mul_pd(x0_im,w1r)); }
        x1_re = LD(&in_re[4*K+k]);
        x1_im = LD(&in_im[4*K+k]);
        { __m256d tr = x1_re;
          x1_re = _mm256_fmsub_pd(x1_re,w4r,_mm256_mul_pd(x1_im,w4i));
          x1_im = _mm256_fmadd_pd(tr,w4i,_mm256_mul_pd(x1_im,w4r)); }
        x2_re = LD(&in_re[7*K+k]);
        x2_im = LD(&in_im[7*K+k]);
        { __m256d tr = x2_re;
          x2_re = _mm256_fmsub_pd(x2_re,w7r,_mm256_mul_pd(x2_im,w7i));
          x2_im = _mm256_fmadd_pd(tr,w7i,_mm256_mul_pd(x2_im,w7r)); }
        x3_re = LD(&in_re[10*K+k]);
        x3_im = LD(&in_im[10*K+k]);
        { __m256d tr = x3_re;
          x3_re = _mm256_fmsub_pd(x3_re,w10r,_mm256_mul_pd(x3_im,w10i));
          x3_im = _mm256_fmadd_pd(tr,w10i,_mm256_mul_pd(x3_im,w10r)); }

        /* radix-4 n2=1 [fwd] */
        {
        __m256d sr=_mm256_add_pd(x0_re,x2_re), si=_mm256_add_pd(x0_im,x2_im);
        __m256d dr=_mm256_sub_pd(x0_re,x2_re), di=_mm256_sub_pd(x0_im,x2_im);
        __m256d tr=_mm256_add_pd(x1_re,x3_re), ti=_mm256_add_pd(x1_im,x3_im);
        __m256d ur=_mm256_sub_pd(x1_re,x3_re), ui=_mm256_sub_pd(x1_im,x3_im);
        x0_re=_mm256_add_pd(sr,tr); x0_im=_mm256_add_pd(si,ti);
        x2_re=_mm256_sub_pd(sr,tr); x2_im=_mm256_sub_pd(si,ti);
        x1_re=_mm256_add_pd(dr,ui); x1_im=_mm256_sub_pd(di,ur);
        x3_re=_mm256_sub_pd(dr,ui); x3_im=_mm256_add_pd(di,ur);
        }

        _mm256_store_pd(&spill_re[4*4], x0_re);
        _mm256_store_pd(&spill_im[4*4], x0_im);
        _mm256_store_pd(&spill_re[5*4], x1_re);
        _mm256_store_pd(&spill_im[5*4], x1_im);
        _mm256_store_pd(&spill_re[6*4], x2_re);
        _mm256_store_pd(&spill_im[6*4], x2_im);
        _mm256_store_pd(&spill_re[7*4], x3_re);
        _mm256_store_pd(&spill_im[7*4], x3_im);

        /* sub-FFT n2=2 */
        x0_re = LD(&in_re[2*K+k]);
        x0_im = LD(&in_im[2*K+k]);
        { __m256d tr = x0_re;
          x0_re = _mm256_fmsub_pd(x0_re,w2r,_mm256_mul_pd(x0_im,w2i));
          x0_im = _mm256_fmadd_pd(tr,w2i,_mm256_mul_pd(x0_im,w2r)); }
        x1_re = LD(&in_re[5*K+k]);
        x1_im = LD(&in_im[5*K+k]);
        { __m256d tr = x1_re;
          x1_re = _mm256_fmsub_pd(x1_re,w5r,_mm256_mul_pd(x1_im,w5i));
          x1_im = _mm256_fmadd_pd(tr,w5i,_mm256_mul_pd(x1_im,w5r)); }
        x2_re = LD(&in_re[8*K+k]);
        x2_im = LD(&in_im[8*K+k]);
        { __m256d tr = x2_re;
          x2_re = _mm256_fmsub_pd(x2_re,w8r,_mm256_mul_pd(x2_im,w8i));
          x2_im = _mm256_fmadd_pd(tr,w8i,_mm256_mul_pd(x2_im,w8r)); }
        x3_re = LD(&in_re[11*K+k]);
        x3_im = LD(&in_im[11*K+k]);
        { __m256d tr = x3_re;
          x3_re = _mm256_fmsub_pd(x3_re,w11r,_mm256_mul_pd(x3_im,w11i));
          x3_im = _mm256_fmadd_pd(tr,w11i,_mm256_mul_pd(x3_im,w11r)); }

        /* radix-4 n2=2 [fwd] */
        {
        __m256d sr=_mm256_add_pd(x0_re,x2_re), si=_mm256_add_pd(x0_im,x2_im);
        __m256d dr=_mm256_sub_pd(x0_re,x2_re), di=_mm256_sub_pd(x0_im,x2_im);
        __m256d tr=_mm256_add_pd(x1_re,x3_re), ti=_mm256_add_pd(x1_im,x3_im);
        __m256d ur=_mm256_sub_pd(x1_re,x3_re), ui=_mm256_sub_pd(x1_im,x3_im);
        x0_re=_mm256_add_pd(sr,tr); x0_im=_mm256_add_pd(si,ti);
        x2_re=_mm256_sub_pd(sr,tr); x2_im=_mm256_sub_pd(si,ti);
        x1_re=_mm256_add_pd(dr,ui); x1_im=_mm256_sub_pd(di,ur);
        x3_re=_mm256_sub_pd(dr,ui); x3_im=_mm256_add_pd(di,ur);
        }

        _mm256_store_pd(&spill_re[8*4], x0_re);
        _mm256_store_pd(&spill_im[8*4], x0_im);
        _mm256_store_pd(&spill_re[9*4], x1_re);
        _mm256_store_pd(&spill_im[9*4], x1_im);
        _mm256_store_pd(&spill_re[10*4], x2_re);
        _mm256_store_pd(&spill_im[10*4], x2_im);
        _mm256_store_pd(&spill_re[11*4], x3_re);
        _mm256_store_pd(&spill_im[11*4], x3_im);

        /* PASS 2: 4x radix-3 columns */

        /* column k1=0 */
        x0_re = _mm256_load_pd(&spill_re[0*4]);
        x0_im = _mm256_load_pd(&spill_im[0*4]);
        x1_re = _mm256_load_pd(&spill_re[4*4]);
        x1_im = _mm256_load_pd(&spill_im[4*4]);
        x2_re = _mm256_load_pd(&spill_re[8*4]);
        x2_im = _mm256_load_pd(&spill_im[8*4]);

        /* radix-3 k1=0 [fwd] */
        {
        __m256d sr=_mm256_add_pd(x1_re,x2_re), si=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d Rr=_mm256_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm256_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm256_add_pd(x0_re,sr); x0_im=_mm256_add_pd(x0_im,si);
        x1_re=_mm256_fmadd_pd(KS,di,Rr); x1_im=_mm256_fnmadd_pd(KS,dr,Ri);
        x2_re=_mm256_fnmadd_pd(KS,di,Rr); x2_im=_mm256_fmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[0*K+k], x0_re);
        ST(&out_im[0*K+k], x0_im);
        ST(&out_re[4*K+k], x1_re);
        ST(&out_im[4*K+k], x1_im);
        ST(&out_re[8*K+k], x2_re);
        ST(&out_im[8*K+k], x2_im);

        /* column k1=1 */
        x0_re = _mm256_load_pd(&spill_re[1*4]);
        x0_im = _mm256_load_pd(&spill_im[1*4]);
        x1_re = _mm256_load_pd(&spill_re[5*4]);
        x1_im = _mm256_load_pd(&spill_im[5*4]);
        x2_re = _mm256_load_pd(&spill_re[9*4]);
        x2_im = _mm256_load_pd(&spill_im[9*4]);

        { __m256d tr = x1_re;
          x1_re = _mm256_fmsub_pd(x1_re,tw_W12_1_re,_mm256_mul_pd(x1_im,tw_W12_1_im));
          x1_im = _mm256_fmadd_pd(tr,tw_W12_1_im,_mm256_mul_pd(x1_im,tw_W12_1_re)); }
        { __m256d tr = x2_re;
          x2_re = _mm256_fmsub_pd(x2_re,tw_W12_2_re,_mm256_mul_pd(x2_im,tw_W12_2_im));
          x2_im = _mm256_fmadd_pd(tr,tw_W12_2_im,_mm256_mul_pd(x2_im,tw_W12_2_re)); }

        /* radix-3 k1=1 [fwd] */
        {
        __m256d sr=_mm256_add_pd(x1_re,x2_re), si=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d Rr=_mm256_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm256_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm256_add_pd(x0_re,sr); x0_im=_mm256_add_pd(x0_im,si);
        x1_re=_mm256_fmadd_pd(KS,di,Rr); x1_im=_mm256_fnmadd_pd(KS,dr,Ri);
        x2_re=_mm256_fnmadd_pd(KS,di,Rr); x2_im=_mm256_fmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[1*K+k], x0_re);
        ST(&out_im[1*K+k], x0_im);
        ST(&out_re[5*K+k], x1_re);
        ST(&out_im[5*K+k], x1_im);
        ST(&out_re[9*K+k], x2_re);
        ST(&out_im[9*K+k], x2_im);

        /* column k1=2 */
        x0_re = _mm256_load_pd(&spill_re[2*4]);
        x0_im = _mm256_load_pd(&spill_im[2*4]);
        x1_re = _mm256_load_pd(&spill_re[6*4]);
        x1_im = _mm256_load_pd(&spill_im[6*4]);
        x2_re = _mm256_load_pd(&spill_re[10*4]);
        x2_im = _mm256_load_pd(&spill_im[10*4]);

        { __m256d tr = x1_re;
          x1_re = _mm256_fmsub_pd(x1_re,tw_W12_2_re,_mm256_mul_pd(x1_im,tw_W12_2_im));
          x1_im = _mm256_fmadd_pd(tr,tw_W12_2_im,_mm256_mul_pd(x1_im,tw_W12_2_re)); }
        { __m256d tr = x2_re;
          x2_re = _mm256_fmsub_pd(x2_re,tw_W12_4_re,_mm256_mul_pd(x2_im,tw_W12_4_im));
          x2_im = _mm256_fmadd_pd(tr,tw_W12_4_im,_mm256_mul_pd(x2_im,tw_W12_4_re)); }

        /* radix-3 k1=2 [fwd] */
        {
        __m256d sr=_mm256_add_pd(x1_re,x2_re), si=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d Rr=_mm256_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm256_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm256_add_pd(x0_re,sr); x0_im=_mm256_add_pd(x0_im,si);
        x1_re=_mm256_fmadd_pd(KS,di,Rr); x1_im=_mm256_fnmadd_pd(KS,dr,Ri);
        x2_re=_mm256_fnmadd_pd(KS,di,Rr); x2_im=_mm256_fmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[2*K+k], x0_re);
        ST(&out_im[2*K+k], x0_im);
        ST(&out_re[6*K+k], x1_re);
        ST(&out_im[6*K+k], x1_im);
        ST(&out_re[10*K+k], x2_re);
        ST(&out_im[10*K+k], x2_im);

        /* column k1=3 */
        x0_re = _mm256_load_pd(&spill_re[3*4]);
        x0_im = _mm256_load_pd(&spill_im[3*4]);
        x1_re = _mm256_load_pd(&spill_re[7*4]);
        x1_im = _mm256_load_pd(&spill_im[7*4]);
        x2_re = _mm256_load_pd(&spill_re[11*4]);
        x2_im = _mm256_load_pd(&spill_im[11*4]);

        { __m256d tr = x1_re; x1_re = x1_im; x1_im = _mm256_xor_pd(tr,sign_flip); }
        x2_re = _mm256_xor_pd(x2_re,sign_flip); x2_im = _mm256_xor_pd(x2_im,sign_flip);

        /* radix-3 k1=3 [fwd] */
        {
        __m256d sr=_mm256_add_pd(x1_re,x2_re), si=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d Rr=_mm256_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm256_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm256_add_pd(x0_re,sr); x0_im=_mm256_add_pd(x0_im,si);
        x1_re=_mm256_fmadd_pd(KS,di,Rr); x1_im=_mm256_fnmadd_pd(KS,dr,Ri);
        x2_re=_mm256_fnmadd_pd(KS,di,Rr); x2_im=_mm256_fmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[3*K+k], x0_re);
        ST(&out_im[3*K+k], x0_im);
        ST(&out_re[7*K+k], x1_re);
        ST(&out_im[7*K+k], x1_im);
        ST(&out_re[11*K+k], x2_re);
        ST(&out_im[11*K+k], x2_im);

    }
}

static __attribute__((target("avx2,fma"))) void
radix12_tw_log3_dit_kernel_bwd_avx2(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ tw_re, const double * __restrict__ tw_im,
    size_t K)
{
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d KHALF = _mm256_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m256d KS = _mm256_set1_pd(0.866025403784438596588302061718422919511795044);

    __attribute__((aligned(32))) double spill_re[48];
    __attribute__((aligned(32))) double spill_im[48];

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im;

    const __m256d tw_W12_1_re = _mm256_set1_pd(W12_1_re);
    const __m256d tw_W12_1_im = _mm256_set1_pd(W12_1_im);
    const __m256d tw_W12_2_re = _mm256_set1_pd(W12_2_re);
    const __m256d tw_W12_2_im = _mm256_set1_pd(W12_2_im);
    const __m256d tw_W12_4_re = _mm256_set1_pd(W12_4_re);
    const __m256d tw_W12_4_im = _mm256_set1_pd(W12_4_im);

    for (size_t k = 0; k < K; k += 4) {
        /* Log3: load W^1, derive W^2..W^11 (10 cmuls, depth-4 parallel chain) */
        const __m256d w1r = _mm256_load_pd(&tw_re[0*K+k]), w1i = _mm256_load_pd(&tw_im[0*K+k]);
        __m256d w2r, w2i;
        w2r = _mm256_fmsub_pd(w1r,w1r,_mm256_mul_pd(w1i,w1i));
        w2i = _mm256_fmadd_pd(w1r,w1i,_mm256_mul_pd(w1i,w1r));
        __m256d w3r, w3i;
        w3r = _mm256_fmsub_pd(w1r,w2r,_mm256_mul_pd(w1i,w2i));
        w3i = _mm256_fmadd_pd(w1r,w2i,_mm256_mul_pd(w1i,w2r));
        __m256d w4r, w4i;
        w4r = _mm256_fmsub_pd(w2r,w2r,_mm256_mul_pd(w2i,w2i));
        w4i = _mm256_fmadd_pd(w2r,w2i,_mm256_mul_pd(w2i,w2r));
        __m256d w5r, w5i;
        w5r = _mm256_fmsub_pd(w1r,w4r,_mm256_mul_pd(w1i,w4i));
        w5i = _mm256_fmadd_pd(w1r,w4i,_mm256_mul_pd(w1i,w4r));
        __m256d w6r, w6i;
        w6r = _mm256_fmsub_pd(w3r,w3r,_mm256_mul_pd(w3i,w3i));
        w6i = _mm256_fmadd_pd(w3r,w3i,_mm256_mul_pd(w3i,w3r));
        __m256d w7r, w7i;
        w7r = _mm256_fmsub_pd(w3r,w4r,_mm256_mul_pd(w3i,w4i));
        w7i = _mm256_fmadd_pd(w3r,w4i,_mm256_mul_pd(w3i,w4r));
        __m256d w8r, w8i;
        w8r = _mm256_fmsub_pd(w4r,w4r,_mm256_mul_pd(w4i,w4i));
        w8i = _mm256_fmadd_pd(w4r,w4i,_mm256_mul_pd(w4i,w4r));
        __m256d w9r, w9i;
        w9r = _mm256_fmsub_pd(w4r,w5r,_mm256_mul_pd(w4i,w5i));
        w9i = _mm256_fmadd_pd(w4r,w5i,_mm256_mul_pd(w4i,w5r));
        __m256d w10r, w10i;
        w10r = _mm256_fmsub_pd(w5r,w5r,_mm256_mul_pd(w5i,w5i));
        w10i = _mm256_fmadd_pd(w5r,w5i,_mm256_mul_pd(w5i,w5r));
        __m256d w11r, w11i;
        w11r = _mm256_fmsub_pd(w5r,w6r,_mm256_mul_pd(w5i,w6i));
        w11i = _mm256_fmadd_pd(w5r,w6i,_mm256_mul_pd(w5i,w6r));

        /* sub-FFT n2=0 */
        x0_re = LD(&in_re[0*K+k]);
        x0_im = LD(&in_im[0*K+k]);
        x1_re = LD(&in_re[3*K+k]);
        x1_im = LD(&in_im[3*K+k]);
        { __m256d tr = x1_re;
          x1_re = _mm256_fmadd_pd(x1_re,w3r,_mm256_mul_pd(x1_im,w3i));
          x1_im = _mm256_fmsub_pd(x1_im,w3r,_mm256_mul_pd(tr,w3i)); }
        x2_re = LD(&in_re[6*K+k]);
        x2_im = LD(&in_im[6*K+k]);
        { __m256d tr = x2_re;
          x2_re = _mm256_fmadd_pd(x2_re,w6r,_mm256_mul_pd(x2_im,w6i));
          x2_im = _mm256_fmsub_pd(x2_im,w6r,_mm256_mul_pd(tr,w6i)); }
        x3_re = LD(&in_re[9*K+k]);
        x3_im = LD(&in_im[9*K+k]);
        { __m256d tr = x3_re;
          x3_re = _mm256_fmadd_pd(x3_re,w9r,_mm256_mul_pd(x3_im,w9i));
          x3_im = _mm256_fmsub_pd(x3_im,w9r,_mm256_mul_pd(tr,w9i)); }

        /* radix-4 n2=0 [bwd] */
        {
        __m256d sr=_mm256_add_pd(x0_re,x2_re), si=_mm256_add_pd(x0_im,x2_im);
        __m256d dr=_mm256_sub_pd(x0_re,x2_re), di=_mm256_sub_pd(x0_im,x2_im);
        __m256d tr=_mm256_add_pd(x1_re,x3_re), ti=_mm256_add_pd(x1_im,x3_im);
        __m256d ur=_mm256_sub_pd(x1_re,x3_re), ui=_mm256_sub_pd(x1_im,x3_im);
        x0_re=_mm256_add_pd(sr,tr); x0_im=_mm256_add_pd(si,ti);
        x2_re=_mm256_sub_pd(sr,tr); x2_im=_mm256_sub_pd(si,ti);
        x1_re=_mm256_sub_pd(dr,ui); x1_im=_mm256_add_pd(di,ur);
        x3_re=_mm256_add_pd(dr,ui); x3_im=_mm256_sub_pd(di,ur);
        }

        _mm256_store_pd(&spill_re[0*4], x0_re);
        _mm256_store_pd(&spill_im[0*4], x0_im);
        _mm256_store_pd(&spill_re[1*4], x1_re);
        _mm256_store_pd(&spill_im[1*4], x1_im);
        _mm256_store_pd(&spill_re[2*4], x2_re);
        _mm256_store_pd(&spill_im[2*4], x2_im);
        _mm256_store_pd(&spill_re[3*4], x3_re);
        _mm256_store_pd(&spill_im[3*4], x3_im);

        /* sub-FFT n2=1 */
        x0_re = LD(&in_re[1*K+k]);
        x0_im = LD(&in_im[1*K+k]);
        { __m256d tr = x0_re;
          x0_re = _mm256_fmadd_pd(x0_re,w1r,_mm256_mul_pd(x0_im,w1i));
          x0_im = _mm256_fmsub_pd(x0_im,w1r,_mm256_mul_pd(tr,w1i)); }
        x1_re = LD(&in_re[4*K+k]);
        x1_im = LD(&in_im[4*K+k]);
        { __m256d tr = x1_re;
          x1_re = _mm256_fmadd_pd(x1_re,w4r,_mm256_mul_pd(x1_im,w4i));
          x1_im = _mm256_fmsub_pd(x1_im,w4r,_mm256_mul_pd(tr,w4i)); }
        x2_re = LD(&in_re[7*K+k]);
        x2_im = LD(&in_im[7*K+k]);
        { __m256d tr = x2_re;
          x2_re = _mm256_fmadd_pd(x2_re,w7r,_mm256_mul_pd(x2_im,w7i));
          x2_im = _mm256_fmsub_pd(x2_im,w7r,_mm256_mul_pd(tr,w7i)); }
        x3_re = LD(&in_re[10*K+k]);
        x3_im = LD(&in_im[10*K+k]);
        { __m256d tr = x3_re;
          x3_re = _mm256_fmadd_pd(x3_re,w10r,_mm256_mul_pd(x3_im,w10i));
          x3_im = _mm256_fmsub_pd(x3_im,w10r,_mm256_mul_pd(tr,w10i)); }

        /* radix-4 n2=1 [bwd] */
        {
        __m256d sr=_mm256_add_pd(x0_re,x2_re), si=_mm256_add_pd(x0_im,x2_im);
        __m256d dr=_mm256_sub_pd(x0_re,x2_re), di=_mm256_sub_pd(x0_im,x2_im);
        __m256d tr=_mm256_add_pd(x1_re,x3_re), ti=_mm256_add_pd(x1_im,x3_im);
        __m256d ur=_mm256_sub_pd(x1_re,x3_re), ui=_mm256_sub_pd(x1_im,x3_im);
        x0_re=_mm256_add_pd(sr,tr); x0_im=_mm256_add_pd(si,ti);
        x2_re=_mm256_sub_pd(sr,tr); x2_im=_mm256_sub_pd(si,ti);
        x1_re=_mm256_sub_pd(dr,ui); x1_im=_mm256_add_pd(di,ur);
        x3_re=_mm256_add_pd(dr,ui); x3_im=_mm256_sub_pd(di,ur);
        }

        _mm256_store_pd(&spill_re[4*4], x0_re);
        _mm256_store_pd(&spill_im[4*4], x0_im);
        _mm256_store_pd(&spill_re[5*4], x1_re);
        _mm256_store_pd(&spill_im[5*4], x1_im);
        _mm256_store_pd(&spill_re[6*4], x2_re);
        _mm256_store_pd(&spill_im[6*4], x2_im);
        _mm256_store_pd(&spill_re[7*4], x3_re);
        _mm256_store_pd(&spill_im[7*4], x3_im);

        /* sub-FFT n2=2 */
        x0_re = LD(&in_re[2*K+k]);
        x0_im = LD(&in_im[2*K+k]);
        { __m256d tr = x0_re;
          x0_re = _mm256_fmadd_pd(x0_re,w2r,_mm256_mul_pd(x0_im,w2i));
          x0_im = _mm256_fmsub_pd(x0_im,w2r,_mm256_mul_pd(tr,w2i)); }
        x1_re = LD(&in_re[5*K+k]);
        x1_im = LD(&in_im[5*K+k]);
        { __m256d tr = x1_re;
          x1_re = _mm256_fmadd_pd(x1_re,w5r,_mm256_mul_pd(x1_im,w5i));
          x1_im = _mm256_fmsub_pd(x1_im,w5r,_mm256_mul_pd(tr,w5i)); }
        x2_re = LD(&in_re[8*K+k]);
        x2_im = LD(&in_im[8*K+k]);
        { __m256d tr = x2_re;
          x2_re = _mm256_fmadd_pd(x2_re,w8r,_mm256_mul_pd(x2_im,w8i));
          x2_im = _mm256_fmsub_pd(x2_im,w8r,_mm256_mul_pd(tr,w8i)); }
        x3_re = LD(&in_re[11*K+k]);
        x3_im = LD(&in_im[11*K+k]);
        { __m256d tr = x3_re;
          x3_re = _mm256_fmadd_pd(x3_re,w11r,_mm256_mul_pd(x3_im,w11i));
          x3_im = _mm256_fmsub_pd(x3_im,w11r,_mm256_mul_pd(tr,w11i)); }

        /* radix-4 n2=2 [bwd] */
        {
        __m256d sr=_mm256_add_pd(x0_re,x2_re), si=_mm256_add_pd(x0_im,x2_im);
        __m256d dr=_mm256_sub_pd(x0_re,x2_re), di=_mm256_sub_pd(x0_im,x2_im);
        __m256d tr=_mm256_add_pd(x1_re,x3_re), ti=_mm256_add_pd(x1_im,x3_im);
        __m256d ur=_mm256_sub_pd(x1_re,x3_re), ui=_mm256_sub_pd(x1_im,x3_im);
        x0_re=_mm256_add_pd(sr,tr); x0_im=_mm256_add_pd(si,ti);
        x2_re=_mm256_sub_pd(sr,tr); x2_im=_mm256_sub_pd(si,ti);
        x1_re=_mm256_sub_pd(dr,ui); x1_im=_mm256_add_pd(di,ur);
        x3_re=_mm256_add_pd(dr,ui); x3_im=_mm256_sub_pd(di,ur);
        }

        _mm256_store_pd(&spill_re[8*4], x0_re);
        _mm256_store_pd(&spill_im[8*4], x0_im);
        _mm256_store_pd(&spill_re[9*4], x1_re);
        _mm256_store_pd(&spill_im[9*4], x1_im);
        _mm256_store_pd(&spill_re[10*4], x2_re);
        _mm256_store_pd(&spill_im[10*4], x2_im);
        _mm256_store_pd(&spill_re[11*4], x3_re);
        _mm256_store_pd(&spill_im[11*4], x3_im);

        /* PASS 2: 4x radix-3 columns */

        /* column k1=0 */
        x0_re = _mm256_load_pd(&spill_re[0*4]);
        x0_im = _mm256_load_pd(&spill_im[0*4]);
        x1_re = _mm256_load_pd(&spill_re[4*4]);
        x1_im = _mm256_load_pd(&spill_im[4*4]);
        x2_re = _mm256_load_pd(&spill_re[8*4]);
        x2_im = _mm256_load_pd(&spill_im[8*4]);

        /* radix-3 k1=0 [bwd] */
        {
        __m256d sr=_mm256_add_pd(x1_re,x2_re), si=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d Rr=_mm256_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm256_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm256_add_pd(x0_re,sr); x0_im=_mm256_add_pd(x0_im,si);
        x1_re=_mm256_fnmadd_pd(KS,di,Rr); x1_im=_mm256_fmadd_pd(KS,dr,Ri);
        x2_re=_mm256_fmadd_pd(KS,di,Rr); x2_im=_mm256_fnmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[0*K+k], x0_re);
        ST(&out_im[0*K+k], x0_im);
        ST(&out_re[4*K+k], x1_re);
        ST(&out_im[4*K+k], x1_im);
        ST(&out_re[8*K+k], x2_re);
        ST(&out_im[8*K+k], x2_im);

        /* column k1=1 */
        x0_re = _mm256_load_pd(&spill_re[1*4]);
        x0_im = _mm256_load_pd(&spill_im[1*4]);
        x1_re = _mm256_load_pd(&spill_re[5*4]);
        x1_im = _mm256_load_pd(&spill_im[5*4]);
        x2_re = _mm256_load_pd(&spill_re[9*4]);
        x2_im = _mm256_load_pd(&spill_im[9*4]);

        { __m256d tr = x1_re;
          x1_re = _mm256_fmadd_pd(x1_re,tw_W12_1_re,_mm256_mul_pd(x1_im,tw_W12_1_im));
          x1_im = _mm256_fmsub_pd(x1_im,tw_W12_1_re,_mm256_mul_pd(tr,tw_W12_1_im)); }
        { __m256d tr = x2_re;
          x2_re = _mm256_fmadd_pd(x2_re,tw_W12_2_re,_mm256_mul_pd(x2_im,tw_W12_2_im));
          x2_im = _mm256_fmsub_pd(x2_im,tw_W12_2_re,_mm256_mul_pd(tr,tw_W12_2_im)); }

        /* radix-3 k1=1 [bwd] */
        {
        __m256d sr=_mm256_add_pd(x1_re,x2_re), si=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d Rr=_mm256_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm256_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm256_add_pd(x0_re,sr); x0_im=_mm256_add_pd(x0_im,si);
        x1_re=_mm256_fnmadd_pd(KS,di,Rr); x1_im=_mm256_fmadd_pd(KS,dr,Ri);
        x2_re=_mm256_fmadd_pd(KS,di,Rr); x2_im=_mm256_fnmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[1*K+k], x0_re);
        ST(&out_im[1*K+k], x0_im);
        ST(&out_re[5*K+k], x1_re);
        ST(&out_im[5*K+k], x1_im);
        ST(&out_re[9*K+k], x2_re);
        ST(&out_im[9*K+k], x2_im);

        /* column k1=2 */
        x0_re = _mm256_load_pd(&spill_re[2*4]);
        x0_im = _mm256_load_pd(&spill_im[2*4]);
        x1_re = _mm256_load_pd(&spill_re[6*4]);
        x1_im = _mm256_load_pd(&spill_im[6*4]);
        x2_re = _mm256_load_pd(&spill_re[10*4]);
        x2_im = _mm256_load_pd(&spill_im[10*4]);

        { __m256d tr = x1_re;
          x1_re = _mm256_fmadd_pd(x1_re,tw_W12_2_re,_mm256_mul_pd(x1_im,tw_W12_2_im));
          x1_im = _mm256_fmsub_pd(x1_im,tw_W12_2_re,_mm256_mul_pd(tr,tw_W12_2_im)); }
        { __m256d tr = x2_re;
          x2_re = _mm256_fmadd_pd(x2_re,tw_W12_4_re,_mm256_mul_pd(x2_im,tw_W12_4_im));
          x2_im = _mm256_fmsub_pd(x2_im,tw_W12_4_re,_mm256_mul_pd(tr,tw_W12_4_im)); }

        /* radix-3 k1=2 [bwd] */
        {
        __m256d sr=_mm256_add_pd(x1_re,x2_re), si=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d Rr=_mm256_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm256_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm256_add_pd(x0_re,sr); x0_im=_mm256_add_pd(x0_im,si);
        x1_re=_mm256_fnmadd_pd(KS,di,Rr); x1_im=_mm256_fmadd_pd(KS,dr,Ri);
        x2_re=_mm256_fmadd_pd(KS,di,Rr); x2_im=_mm256_fnmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[2*K+k], x0_re);
        ST(&out_im[2*K+k], x0_im);
        ST(&out_re[6*K+k], x1_re);
        ST(&out_im[6*K+k], x1_im);
        ST(&out_re[10*K+k], x2_re);
        ST(&out_im[10*K+k], x2_im);

        /* column k1=3 */
        x0_re = _mm256_load_pd(&spill_re[3*4]);
        x0_im = _mm256_load_pd(&spill_im[3*4]);
        x1_re = _mm256_load_pd(&spill_re[7*4]);
        x1_im = _mm256_load_pd(&spill_im[7*4]);
        x2_re = _mm256_load_pd(&spill_re[11*4]);
        x2_im = _mm256_load_pd(&spill_im[11*4]);

        { __m256d tr = x1_re; x1_re = _mm256_xor_pd(x1_im,sign_flip); x1_im = tr; }
        x2_re = _mm256_xor_pd(x2_re,sign_flip); x2_im = _mm256_xor_pd(x2_im,sign_flip);

        /* radix-3 k1=3 [bwd] */
        {
        __m256d sr=_mm256_add_pd(x1_re,x2_re), si=_mm256_add_pd(x1_im,x2_im);
        __m256d dr=_mm256_sub_pd(x1_re,x2_re), di=_mm256_sub_pd(x1_im,x2_im);
        __m256d Rr=_mm256_fnmadd_pd(KHALF,sr,x0_re), Ri=_mm256_fnmadd_pd(KHALF,si,x0_im);
        x0_re=_mm256_add_pd(x0_re,sr); x0_im=_mm256_add_pd(x0_im,si);
        x1_re=_mm256_fnmadd_pd(KS,di,Rr); x1_im=_mm256_fmadd_pd(KS,dr,Ri);
        x2_re=_mm256_fmadd_pd(KS,di,Rr); x2_im=_mm256_fnmadd_pd(KS,dr,Ri);
        }

        ST(&out_re[3*K+k], x0_re);
        ST(&out_im[3*K+k], x0_im);
        ST(&out_re[7*K+k], x1_re);
        ST(&out_im[7*K+k], x1_im);
        ST(&out_re[11*K+k], x2_re);
        ST(&out_im[11*K+k], x2_im);

    }
}

#undef LD
#undef ST

#endif /* FFT_RADIX12_AVX2_DIT_TW_LOG3_H */
